// 1. Забираем сырой текст из AI Agent
let text =
  $json.output ??
  $json.text ??
  $json.message?.content ??
  $json.message?.text ??
  "";

// 2. Защита от объектов (если ИИ вернул JSON вместо строки)
if (typeof text === 'object' && text !== null) {
  text = JSON.stringify(text, null, 2);
} else {
  text = String(text).trim();
}

// 3. Защита от пустоты
if (!text) {
  text = "Бот вернул пустое сообщение.";
}

// 4. Очистка от ВСЕХ скрытых символов разметки Markdown,
// которые ИИ обожает ставить (точки в списках, дефисы, звездочки)
text = text.replace(/[_*\[\]()~`>#+\-=|{}.!]/g, "");

// 5. Защита от слишком длинных ответов ИИ (лимит Telegram — 4096)
if (text.length > 4000) {
  text = text.substring(0, 4000) + "\n...[Текст обрезан из-за лимита длины]";
}

// 6. Передаем чистый текст дальше в узел Telegram
return [{
  json: {
    text: text
  }
}];
